WITH comps AS (SELECT node, component FROM pgr_connectedComponents('SELECT id, source, target, cost, reverse_cost FROM ways WHERE cost IS NOT NULL')), main AS (SELECT component FROM comps GROUP BY component ORDER BY count(*) DESC LIMIT 1) SELECT * FROM pgr_dijkstra('SELECT id, source, target, cost, reverse_cost FROM ways WHERE cost IS NOT NULL', (SELECT w.source FROM ways w JOIN comps c ON w.source = c.node WHERE c.component = (SELECT component FROM main) ORDER BY random() LIMIT 1), (SELECT w.target FROM ways w JOIN comps c ON w.target = c.node WHERE c.component = (SELECT component FROM main) ORDER BY random() LIMIT 1), directed := false) LIMIT 5;
